import type { NextConfig } from "next";

const nextConfig: NextConfig = {
  cacheComponents: true
};

export default nextConfig;


// app/admin/products/page.tsx
import { cacheLife, cacheTag, updateTag } from "next/cache";
import { getAllProducts, syncAllProducts } from "@/lib/db";

// ---------------------------------------------------------------------------
// Cache-tagged data fetcher
// ---------------------------------------------------------------------------

async function getCachedProducts() {
  "use cache";
  cacheTag("products");
  cacheLife({ stale: 300, revalidate: 3600 });

  return getAllProducts();
}

// ---------------------------------------------------------------------------
// Product row component
// ---------------------------------------------------------------------------

function ProductRow({
  product
}: {
  product: {
    id: number;
    name: string;
    price: number;
    inStock: boolean;
    sku: string;
    category: string;
  };
}) {
  return (
    <tr>
      <td style={cellStyle}>{product.sku}</td>
      <td style={cellStyle}>{product.name}</td>
      <td style={cellStyle}>{product.category}</td>
      <td style={cellStyle}>${product.price.toFixed(2)}</td>
      <td style={cellStyle}>
        <span
          style={{
            ...statusDot,
            backgroundColor: product.inStock ? "#16a34a" : "#dc2626"
          }}
        />
        {product.inStock ? "In stock" : "Out of stock"}
      </td>
    </tr>
  );
}

// ---------------------------------------------------------------------------
// Product table
// ---------------------------------------------------------------------------

async function ProductTable() {
  const products = await getCachedProducts();

  return (
    <table style={tableStyle}>
      <thead>
        <tr>
          <th style={thStyle}>SKU</th>
          <th style={thStyle}>Name</th>
          <th style={thStyle}>Category</th>
          <th style={thStyle}>Price</th>
          <th style={thStyle}>Availability</th>
        </tr>
      </thead>
      <tbody>
        {products.map(product => (
          <ProductRow key={product.id} product={product} />
        ))}
      </tbody>
    </table>
  );
}

// ---------------------------------------------------------------------------
// Admin Catalog Page
// ---------------------------------------------------------------------------

export default function AdminProductsPage() {
  // Inline Server Action — fires a background catalog sync and invalidates
  // the "products" cache tag once the sync completes so subsequent views
  // pick up the freshest data.
  async function syncCatalog(formData: FormData) {
    "use server";

    // Kick off a background sync — do NOT await it so the form submission
    // returns immediately and the admin can keep working.
    syncAllProducts().then(result => {
      console.log(
        `[catalog-sync] completed at ${result.timestamp}, ${result.productsUpdated} products updated`
      );
      updateTag("products");
    });

